insert into market_inventory_unit(
    listing_id, seller_user_id, payload_type, payload_content, status, reserved_order_id, delivered_at
)
values(
    #{listingId}, #{sellerUserId}, #{payloadType}, #{payloadContent}, #{status}, #{reservedOrderId}, #{deliveredAt}
)

