update market_inventory_unit
set status = 'INVALID'
where inventory_unit_id = #{inventoryUnitId}
  and seller_user_id = #{sellerUserId}
  and status = 'AVAILABLE'

update market_inventory_unit
set status = 'RESERVED',
    reserved_order_id = #{reservedOrderId}
where inventory_unit_id = #{inventoryUnitId}
  and status = 'AVAILABLE'

update market_inventory_unit
set status = #{status},
    delivered_at = #{deliveredAt}
where reserved_order_id = #{reservedOrderId}
  and status = 'RESERVED'
